607 /// Creates a VPWidenIntOrFpInductionRecipe or VPWidenPointerInductionRecipe
608 /// for \p Phi based on \p IndDesc.
609 static VPHeaderPHIRecipe *
610 createWidenInductionRecipe(PHINode *Phi, VPPhi *PhiR, VPIRValue *Start,
611                            const InductionDescriptor &IndDesc, VPlan &Plan,
612                            PredicatedScalarEvolution &PSE, Loop &OrigLoop,
613                            DebugLoc DL) {
614   [[maybe_unused]] ScalarEvolution &SE = *PSE.getSE();
615   assert(SE.isLoopInvariant(IndDesc.getStep(), &OrigLoop) &&
616          "step must be loop invariant");
617   assert((Plan.getLiveIn(IndDesc.getStartValue()) == Start ||
618           (SE.isSCEVable(IndDesc.getStartValue()->getType()) &&
619            SE.getSCEV(IndDesc.getStartValue()) ==
620                vputils::getSCEVExprForVPValue(Start, PSE))) &&
621          "Start VPValue must match IndDesc's start value");
622 
623   VPValue *Step =
624       vputils::getOrCreateVPValueForSCEVExpr(Plan, IndDesc.getStep());
625 
626   VPValue *BackedgeVal = PhiR->getOperand(1);
627   // Replace live-out extracts of WideIV's backedge value by ExitingIVValue
628   // recipes. optimizeInductionExitUsers will later compute the proper
629   // DerivedIV.
630   auto ReplaceExtractsWithExitingIVValue = [&](VPHeaderPHIRecipe *WideIV) {
631     for (VPUser *U : to_vector(BackedgeVal->users())) {
632       if (!match(U, m_ExtractLastPart(m_VPValue())))
633         continue;
634       auto *ExtractLastPart = cast<VPInstruction>(U);
635       VPUser *ExtractLastPartUser = ExtractLastPart->getSingleUser();
636       assert(ExtractLastPartUser && "must have a single user");
637       if (!match(ExtractLastPartUser, m_ExtractLastLane(m_VPValue())))
638         continue;
639       auto *ExtractLastLane = cast<VPInstruction>(ExtractLastPartUser);
640       assert(is_contained(ExtractLastLane->getParent()->successors(),
641                           Plan.getScalarPreheader()) &&
642              "last lane must be extracted in the middle block");
643       VPBuilder Builder(ExtractLastLane);
644       ExtractLastLane->replaceAllUsesWith(Builder.createNaryOp(
645           VPInstruction::ExitingIVValue, {WideIV, BackedgeVal}));
646       ExtractLastLane->eraseFromParent();
647       ExtractLastPart->eraseFromParent();
648     }
649   };
650 
651   if (IndDesc.getKind() == InductionDescriptor::IK_PtrInduction) {
652     auto *WideIV = new VPWidenPointerInductionRecipe(
653         Phi, Start, Step, &Plan.getVFxUF(), IndDesc, DL);
654     ReplaceExtractsWithExitingIVValue(WideIV);
655     return WideIV;
656   }
657 
658   assert((IndDesc.getKind() == InductionDescriptor::IK_IntInduction ||
659           IndDesc.getKind() == InductionDescriptor::IK_FpInduction) &&
660          "must have an integer or float induction at this point");
661 
662   // Update wide induction increments to use the same step as the corresponding
663   // wide induction. This enables detecting induction increments directly in
664   // VPlan and removes redundant splats.
665   if (match(BackedgeVal, m_Add(m_Specific(PhiR), m_VPValue())))
666     BackedgeVal->getDefiningRecipe()->setOperand(1, Step);
667 
668   // It is always safe to copy over the NoWrap and FastMath flags. In
669   // particular, when folding tail by masking, the masked-off lanes are never
670   // used, so it is safe.
671   VPIRFlags Flags = vputils::getFlagsFromIndDesc(IndDesc);
672 
673   auto *WideIV = new VPWidenIntOrFpInductionRecipe(
674       Phi, Start, Step, &Plan.getVF(), IndDesc, Flags, DL);
675 
676   ReplaceExtractsWithExitingIVValue(WideIV);
677   return WideIV;
678 }
