680 void VPlanTransforms::createHeaderPhiRecipes(
681     VPlan &Plan, PredicatedScalarEvolution &PSE, Loop &OrigLoop,
682     const MapVector<PHINode *, InductionDescriptor> &Inductions,
683     const MapVector<PHINode *, RecurrenceDescriptor> &Reductions,
684     const SmallPtrSetImpl<const PHINode *> &FixedOrderRecurrences,
685     const SmallPtrSetImpl<PHINode *> &InLoopReductions, bool AllowReordering) {
686   // Retrieve the header manually from the intial plain-CFG VPlan.
687   VPBasicBlock *HeaderVPBB = cast<VPBasicBlock>(
688       Plan.getEntry()->getSuccessors()[1]->getSingleSuccessor());
689   assert(VPDominatorTree(Plan).dominates(HeaderVPBB,
690                                          HeaderVPBB->getPredecessors()[1]) &&
691          "header must dominate its latch");
692 
693   auto CreateHeaderPhiRecipe = [&](VPPhi *PhiR) -> VPHeaderPHIRecipe * {
694     // TODO: Gradually replace uses of underlying instruction by analyses on
695     // VPlan.
696     auto *Phi = cast<PHINode>(PhiR->getUnderlyingInstr());
697     assert(PhiR->getNumOperands() == 2 &&
698            "Must have 2 operands for header phis");
699 
700     // Extract common values once.
701     VPIRValue *Start = cast<VPIRValue>(PhiR->getOperand(0));
702     VPValue *BackedgeValue = PhiR->getOperand(1);
703 
704     if (FixedOrderRecurrences.contains(Phi)) {
705       // TODO: Currently fixed-order recurrences are modeled as chains of
706       // first-order recurrences. If there are no users of the intermediate
707       // recurrences in the chain, the fixed order recurrence should be
708       // modeled directly, enabling more efficient codegen.
709       return new VPFirstOrderRecurrencePHIRecipe(Phi, *Start, *BackedgeValue);
710     }
711 
712     auto InductionIt = Inductions.find(Phi);
713     if (InductionIt != Inductions.end())
714       return createWidenInductionRecipe(Phi, PhiR, Start, InductionIt->second,
715                                         Plan, PSE, OrigLoop,
716                                         PhiR->getDebugLoc());
717 
718     assert(Reductions.contains(Phi) && "only reductions are expected now");
719     const RecurrenceDescriptor &RdxDesc = Reductions.lookup(Phi);
720     assert(RdxDesc.getRecurrenceStartValue() ==
721                Phi->getIncomingValueForBlock(OrigLoop.getLoopPreheader()) &&
722            "incoming value must match start value");
723     // Will be updated later to >1 if reduction is partial.
724     unsigned ScaleFactor = 1;
725     bool UseOrderedReductions = !AllowReordering && RdxDesc.isOrdered();
726     return new VPReductionPHIRecipe(
727         Phi, RdxDesc.getRecurrenceKind(), *Start, *BackedgeValue,
728         getReductionStyle(InLoopReductions.contains(Phi), UseOrderedReductions,
729                           ScaleFactor),
730         RdxDesc.hasUsesOutsideReductionChain());
731   };
732 
733   for (VPRecipeBase &R : make_early_inc_range(HeaderVPBB->phis())) {
734     if (isa<VPCanonicalIVPHIRecipe>(&R))
735       continue;
736     auto *PhiR = cast<VPPhi>(&R);
737     VPHeaderPHIRecipe *HeaderPhiR = CreateHeaderPhiRecipe(PhiR);
738     HeaderPhiR->insertBefore(PhiR);
739     PhiR->replaceAllUsesWith(HeaderPhiR);
740     PhiR->eraseFromParent();
741   }
742 }
