1043 void VPlanTransforms::optimizeInductionExitUsers(
1044     VPlan &Plan, DenseMap<VPValue *, VPValue *> &EndValues,
1045     PredicatedScalarEvolution &PSE) {
1046   VPBlockBase *MiddleVPBB = Plan.getMiddleBlock();
1047   VPTypeAnalysis TypeInfo(Plan);
1048   for (VPIRBasicBlock *ExitVPBB : Plan.getExitBlocks()) {
1049     for (VPRecipeBase &R : ExitVPBB->phis()) {
1050       auto *ExitIRI = cast<VPIRPhi>(&R);
1051 
1052       for (auto [Idx, PredVPBB] : enumerate(ExitVPBB->getPredecessors())) {
1053         VPValue *Escape = nullptr;
1054         if (PredVPBB == MiddleVPBB)
1055           Escape = optimizeLatchExitInductionUser(Plan, TypeInfo, PredVPBB,
1056                                                   ExitIRI->getOperand(Idx),
1057                                                   EndValues, PSE);
1058         else
1059           Escape = optimizeEarlyExitInductionUser(
1060               Plan, TypeInfo, PredVPBB, ExitIRI->getOperand(Idx), PSE);
1061         if (Escape)
1062           ExitIRI->setOperand(Idx, Escape);
1063       }
1064     }
1065   }
1066 }
