1087 static void recursivelyDeleteDeadRecipes(VPValue *V) {
1088   SmallVector<VPValue *> WorkList;
1089   SmallPtrSet<VPValue *, 8> Seen;
1090   WorkList.push_back(V);
1091 
1092   while (!WorkList.empty()) {
1093     VPValue *Cur = WorkList.pop_back_val();
1094     if (!Seen.insert(Cur).second)
1095       continue;
1096     VPRecipeBase *R = Cur->getDefiningRecipe();
1097     if (!R)
1098       continue;
1099     if (!isDeadRecipe(*R))
1100       continue;
1101     append_range(WorkList, R->operands());
1102     R->eraseFromParent();
1103   }
