1106 /// Get any instruction opcode or intrinsic ID data embedded in recipe \p R.
1107 /// Returns an optional pair, where the first element indicates whether it is
1108 /// an intrinsic ID.
1109 static std::optional<std::pair<bool, unsigned>>
1110 getOpcodeOrIntrinsicID(const VPSingleDefRecipe *R) {
1111   return TypeSwitch<const VPSingleDefRecipe *,
1112                     std::optional<std::pair<bool, unsigned>>>(R)
1113       .Case<VPInstruction, VPWidenRecipe, VPWidenCastRecipe, VPWidenGEPRecipe,
1114             VPReplicateRecipe>(
1115           [](auto *I) { return std::make_pair(false, I->getOpcode()); })
1116       .Case([](const VPWidenIntrinsicRecipe *I) {
1117         return std::make_pair(true, I->getVectorIntrinsicID());
1118       })
1119       .Case<VPVectorPointerRecipe, VPPredInstPHIRecipe>([](auto *I) {
1120         // For recipes that do not directly map to LLVM IR instructions,
1121         // assign opcodes after the last VPInstruction opcode (which is also
1122         // after the last IR Instruction opcode), based on the VPRecipeID.
1123         return std::make_pair(false,
1124                               VPInstruction::OpsEnd + 1 + I->getVPRecipeID());
1125       })
1126       .Default([](auto *) { return std::nullopt; });
1127 }
