848     for (unsigned Idx = 1; Idx != getNumOperands(); ++Idx) {
849       Value *VectorStart =
850           Builder.CreateMul(RuntimeVF, ConstantInt::get(IdxTy, Idx - 1));
851       Value *VectorIdx = Idx == 1
