853                              : Builder.CreateSub(LaneToExtract, VectorStart);
854       Value *Ext = State.VF.isScalar()
855                        ? State.get(getOperand(Idx))
856                        : Builder.CreateExtractElement(
857                              State.get(getOperand(Idx)), VectorIdx);
