887                     Builder.getInt64Ty(), State.get(getOperand(Idx)),
888                     /*ZeroIsPoison=*/false, Name);
889       Value *Current = Builder.CreateAdd(
890           Builder.CreateMul(RuntimeVF, Builder.getInt64(Idx)), TrailingZeros);
891       if (Res) {
892         Value *Cmp = Builder.CreateICmpNE(TrailingZeros, RuntimeVF);
