900   }
901   case VPInstruction::ResumeForEpilogue:
902     return State.get(getOperand(0), true);
903   case VPInstruction::Reverse:
904     return Builder.CreateVectorReverse(State.get(getOperand(0)), "reverse");
905   case VPInstruction::ExtractLastActive: {
906     Value *Data = State.get(getOperand(0));
907     Value *Mask = State.get(getOperand(1));
908     Value *Default = State.get(getOperand(2), /*IsScalar=*/true);
909     Type *VTy = Data->getType();
910     return Builder.CreateIntrinsic(
911         Intrinsic::experimental_vector_extract_last_active, {VTy},
912         {Data, Mask, Default});
913   }
914   default:
915     llvm_unreachable("Unsupported opcode for instruction");
916   }
