 995 static VPValue *optimizeLatchExitInductionUser(
 996     VPlan &Plan, VPTypeAnalysis &TypeInfo, VPBlockBase *PredVPBB, VPValue *Op,
 997     DenseMap<VPValue *, VPValue *> &EndValues, PredicatedScalarEvolution &PSE) {
 998   VPValue *Incoming;
 999   VPWidenInductionRecipe *WideIV = nullptr;
1000   if (match(Op, m_ExitingIVValue(m_VPValue(), m_VPValue(Incoming)))) {
1001     WideIV = getOptimizableIVOf(Op->getDefiningRecipe()->getOperand(0), PSE);
1002     assert(WideIV && "must have an optimizable IV");
1003   } else if (match(Op, m_ExtractLastLaneOfLastPart(m_VPValue(Incoming)))) {
1004     WideIV = getOptimizableIVOf(Incoming, PSE);
1005   }
1006 
1007   if (!WideIV)
1008     return nullptr;
1009 
1010   VPValue *EndValue = EndValues.lookup(WideIV);
1011   assert(EndValue && "end value must have been pre-computed");
1012 
1013   // `getOptimizableIVOf()` always returns the pre-incremented IV, so if it
1014   // changed it means the exit is using the incremented value, so we don't
1015   // need to subtract the step.
1016   if (Incoming != WideIV)
1017     return EndValue;
1018 
1019   // Otherwise, subtract the step from the EndValue.
1020   VPBuilder B(cast<VPBasicBlock>(PredVPBB)->getTerminator());
1021   VPValue *Step = WideIV->getStepValue();
1022   Type *ScalarTy = TypeInfo.inferScalarType(WideIV);
1023   if (ScalarTy->isIntegerTy())
1024     return B.createSub(EndValue, Step, DebugLoc::getUnknown(), "ind.escape");
1025   if (ScalarTy->isPointerTy()) {
1026     Type *StepTy = TypeInfo.inferScalarType(Step);
1027     auto *Zero = Plan.getConstantInt(StepTy, 0);
1028     return B.createPtrAdd(EndValue, B.createSub(Zero, Step),
1029                           DebugLoc::getUnknown(), "ind.escape");
1030   }
1031   if (ScalarTy->isFloatingPointTy()) {
1032     const auto &ID = WideIV->getInductionDescriptor();
1033     return B.createNaryOp(
1034         ID.getInductionBinOp()->getOpcode() == Instruction::FAdd
1035             ? Instruction::FSub
1036             : Instruction::FAdd,
1037         {EndValue, Step}, {ID.getInductionBinOp()->getFastMathFlags()});
1038   }
1039   llvm_unreachable("all possible induction types must be handled");
1040   return nullptr;
