 790 /// Legalize VPWidenPointerInductionRecipe, by replacing it with a PtrAdd
 791 /// (IndStart, ScalarIVSteps (0, Step)) if only its scalar values are used, as
 792 /// VPWidenPointerInductionRecipe will generate vectors only. If some users
 793 /// require vectors while other require scalars, the scalar uses need to extract
 794 /// the scalars from the generated vectors (Note that this is different to how
 795 /// int/fp inductions are handled). Legalize extract-from-ends using uniform
 796 /// VPReplicateRecipe of wide inductions to use regular VPReplicateRecipe, so
 797 /// the correct end value is available. Also optimize
 798 /// VPWidenIntOrFpInductionRecipe, if any of its users needs scalar values, by
 799 /// providing them scalar steps built on the canonical scalar IV and update the
 800 /// original IV's users. This is an optional optimization to reduce the needs of
 801 /// vector extracts.
 802 static void legalizeAndOptimizeInductions(VPlan &Plan) {
 803   VPBasicBlock *HeaderVPBB = Plan.getVectorLoopRegion()->getEntryBasicBlock();
 804   bool HasOnlyVectorVFs = !Plan.hasScalarVFOnly();
 805   VPBuilder Builder(HeaderVPBB, HeaderVPBB->getFirstNonPhi());
 806   for (VPRecipeBase &Phi : HeaderVPBB->phis()) {
 807     auto *PhiR = dyn_cast<VPWidenInductionRecipe>(&Phi);
 808     if (!PhiR)
 809       continue;
 810 
 811     // Try to narrow wide and replicating recipes to uniform recipes, based on
 812     // VPlan analysis.
 813     // TODO: Apply to all recipes in the future, to replace legacy uniformity
 814     // analysis.
 815     auto Users = collectUsersRecursively(PhiR);
 816     for (VPUser *U : reverse(Users)) {
 817       auto *Def = dyn_cast<VPRecipeWithIRFlags>(U);
 818       auto *RepR = dyn_cast<VPReplicateRecipe>(U);
 819       // Skip recipes that shouldn't be narrowed.
 820       if (!Def || !isa<VPReplicateRecipe, VPWidenRecipe>(Def) ||
 821           Def->getNumUsers() == 0 || !Def->getUnderlyingValue() ||
 822           (RepR && (RepR->isSingleScalar() || RepR->isPredicated())))
 823         continue;
 824 
 825       // Skip recipes that may have other lanes than their first used.
 826       if (!vputils::isSingleScalar(Def) && !vputils::onlyFirstLaneUsed(Def))
 827         continue;
 828 
 829       auto *Clone = new VPReplicateRecipe(Def->getUnderlyingInstr(),
 830                                           Def->operands(), /*IsUniform*/ true,
 831                                           /*Mask*/ nullptr, /*Flags*/ *Def);
 832       Clone->insertAfter(Def);
 833       Def->replaceAllUsesWith(Clone);
 834     }
 835 
 836     // Replace wide pointer inductions which have only their scalars used by
 837     // PtrAdd(IndStart, ScalarIVSteps (0, Step)).
 838     if (auto *PtrIV = dyn_cast<VPWidenPointerInductionRecipe>(&Phi)) {
 839       if (!Plan.hasScalarVFOnly() &&
 840           !PtrIV->onlyScalarsGenerated(Plan.hasScalableVF()))
 841         continue;
 842 
 843       VPValue *PtrAdd = scalarizeVPWidenPointerInduction(PtrIV, Plan, Builder);
 844       PtrIV->replaceAllUsesWith(PtrAdd);
 845       continue;
 846     }
 847 
 848     // Replace widened induction with scalar steps for users that only use
 849     // scalars.
 850     auto *WideIV = cast<VPWidenIntOrFpInductionRecipe>(&Phi);
 851     if (HasOnlyVectorVFs && none_of(WideIV->users(), [WideIV](VPUser *U) {
 852           return U->usesScalars(WideIV);
 853         }))
 854       continue;
 855 
 856     const InductionDescriptor &ID = WideIV->getInductionDescriptor();
 857     VPScalarIVStepsRecipe *Steps = createScalarIVSteps(
 858         Plan, ID.getKind(), ID.getInductionOpcode(),
 859         dyn_cast_or_null<FPMathOperator>(ID.getInductionBinOp()),
 860         WideIV->getTruncInst(), WideIV->getStartValue(), WideIV->getStepValue(),
 861         WideIV->getDebugLoc(), Builder);
 862 
 863     // Update scalar users of IV to use Step instead.
 864     if (!HasOnlyVectorVFs) {
 865       assert(!Plan.hasScalableVF() &&
 866              "plans containing a scalar VF cannot also include scalable VFs");
 867       WideIV->replaceAllUsesWith(Steps);
 868     } else {
 869       bool HasScalableVF = Plan.hasScalableVF();
 870       WideIV->replaceUsesWithIf(Steps,
 871                                 [WideIV, HasScalableVF](VPUser &U, unsigned) {
 872                                   if (HasScalableVF)
 873                                     return U.usesFirstLaneOnly(WideIV);
 874                                   return U.usesScalars(WideIV);
 875                                 });
 876     }
 877   }
 878 }
