5581     // This is the second phase of vectorizing first-order recurrences, creating
5582     // extract for users outside the loop. An overview of the transformation is
5583     // described below. Suppose we have the following loop with some use after
5584     // the loop of the last a[i-1],
5585     //
5586     //   for (int i = 0; i < n; ++i) {
5587     //     t = a[i - 1];
5588     //     b[i] = a[i] - t;
5589     //   }
5590     //   use t;
5591     //
5592     // There is a first-order recurrence on "a". For this loop, the shorthand
5593     // scalar IR looks like:
5594     //
5595     //   scalar.ph:
5596     //     s.init = a[-1]
5597     //     br scalar.body
5598     //
5599     //   scalar.body:
5600     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5601     //     s1 = phi [s.init, scalar.ph], [s2, scalar.body]
5602     //     s2 = a[i]
5603     //     b[i] = s2 - s1
5604     //     br cond, scalar.body, exit.block
5605     //
5606     //   exit.block:
5607     //     use = lcssa.phi [s1, scalar.body]
5608     //
5609     // In this example, s1 is a recurrence because it's value depends on the
5610     // previous iteration. In the first phase of vectorization, we created a
5611     // VPFirstOrderRecurrencePHIRecipe v1 for s1. Now we create the extracts
5612     // for users in the scalar preheader and exit block.
5613     //
5614     //   vector.ph:
5615     //     v_init = vector(..., ..., ..., a[-1])
5616     //     br vector.body
5617     //
5618     //   vector.body
5619     //     i = phi [0, vector.ph], [i+4, vector.body]
5620     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
5621     //     v2 = a[i, i+1, i+2, i+3]
5622     //     b[i] = v2 - v1
5623     //     // Next, third phase will introduce v1' = splice(v1(3), v2(0, 1, 2))
5624     //     b[i, i+1, i+2, i+3] = v2 - v1
5625     //     br cond, vector.body, middle.block
5626     //
5627     //   middle.block:
5628     //     vector.recur.extract.for.phi = v2(2)
5629     //     vector.recur.extract = v2(3)
5630     //     br cond, scalar.ph, exit.block
5631     //
5632     //   scalar.ph:
5633     //     scalar.recur.init = phi [vector.recur.extract, middle.block],
5634     //                             [s.init, otherwise]
5635     //     br scalar.body
5636     //
5637     //   scalar.body:
5638     //     i = phi [0, scalar.ph], [i+1, scalar.body]
5639     //     s1 = phi [scalar.recur.init, scalar.ph], [s2, scalar.body]
5640     //     s2 = a[i]
5641     //     b[i] = s2 - s1
5642     //     br cond, scalar.body, exit.block
5643     //
5644     //   exit.block:
5645     //     lo = lcssa.phi [s1, scalar.body],
5646     //                    [vector.recur.extract.for.phi, middle.block]
5647     //
5648     // Now update VPIRInstructions modeling LCSSA phis in the exit block.
5649     // Extract the penultimate value of the recurrence and use it as operand for
5650     // the VPIRInstruction modeling the phi.
5651     for (VPRecipeBase &R : make_early_inc_range(
5652              make_range(MiddleVPBB->getFirstNonPhi(), MiddleVPBB->end()))) {
5653       if (!match(&R, m_ExtractLastLaneOfLastPart(m_Specific(FOR))))
5654         continue;
5655 
5656       // For VF vscale x 1, if vscale = 1, we are unable to extract the
5657       // penultimate value of the recurrence. Instead we rely on the existing
5658       // extract of the last element from the result of
5659       // VPInstruction::FirstOrderRecurrenceSplice.
5660       // TODO: Consider vscale_range info and UF.
5661       if (LoopVectorizationPlanner::getDecisionAndClampRange(IsScalableOne,
5662                                                              Range))
5663         return;
5664       VPValue *PenultimateElement = MiddleBuilder.createNaryOp(
5665           VPInstruction::ExtractPenultimateElement, FOR->getBackedgeValue(), {},
5666           "vector.recur.extract.for.phi");
5667       cast<VPInstruction>(&R)->replaceAllUsesWith(PenultimateElement);
5668     }
5669   }
5670 }
