3953       if (auto *Blend = dyn_cast<VPBlendRecipe>(&R)) {
3954         VPValue *Select = Blend->getIncomingValue(0);
3955         for (unsigned I = 1; I != Blend->getNumIncomingValues(); ++I)
3956           Select = Builder.createSelect(Blend->getMask(I),
3957                                         Blend->getIncomingValue(I), Select,
3958                                         R.getDebugLoc(), "predphi", *Blend);
3959         Blend->replaceAllUsesWith(Select);
3960         ToRemove.push_back(Blend);
3961       }
3962 
3963       if (auto *VEPR = dyn_cast<VPVectorEndPointerRecipe>(&R)) {
3964         if (!VEPR->getOffset()) {
3965           assert(Plan.getConcreteUF() == 1 &&
3966                  "Expected unroller to have materialized offset for UF != 1");
3967           VEPR->materializeOffset();
3968         }
3969       }
3970 
3971       if (auto *Expr = dyn_cast<VPExpressionRecipe>(&R)) {
3972         Expr->decompose();
3973         ToRemove.push_back(Expr);
3974       }
3975 
3976       // Expand LastActiveLane into Not + FirstActiveLane + Sub.
3977       auto *LastActiveL = dyn_cast<VPInstruction>(&R);
3978       if (LastActiveL &&
3979           LastActiveL->getOpcode() == VPInstruction::LastActiveLane) {
3980         // Create Not(Mask) for all operands.
3981         SmallVector<VPValue *, 2> NotMasks;
3982         for (VPValue *Op : LastActiveL->operands()) {
3983           VPValue *NotMask = Builder.createNot(Op, LastActiveL->getDebugLoc());
3984           NotMasks.push_back(NotMask);
3985         }
3986 
3987         // Create FirstActiveLane on the inverted masks.
3988         VPValue *FirstInactiveLane = Builder.createNaryOp(
3989             VPInstruction::FirstActiveLane, NotMasks,
3990             LastActiveL->getDebugLoc(), "first.inactive.lane");
3991 
3992         // Subtract 1 to get the last active lane.
3993         VPValue *One = Plan.getConstantInt(64, 1);
3994         VPValue *LastLane =
3995             Builder.createSub(FirstInactiveLane, One,
3996                               LastActiveL->getDebugLoc(), "last.active.lane");
3997 
3998         LastActiveL->replaceAllUsesWith(LastLane);
3999         ToRemove.push_back(LastActiveL);
4000         continue;
4001       }
4002 
4003       // Lower BranchOnCount to ICmp + BranchOnCond.
4004       VPValue *IV, *TC;
4005       if (match(&R, m_BranchOnCount(m_VPValue(IV), m_VPValue(TC)))) {
4006         auto *BranchOnCountInst = cast<VPInstruction>(&R);
4007         DebugLoc DL = BranchOnCountInst->getDebugLoc();
4008         VPValue *Cond = Builder.createICmp(CmpInst::ICMP_EQ, IV, TC, DL);
4009         Builder.createNaryOp(VPInstruction::BranchOnCond, Cond, DL);
4010         ToRemove.push_back(BranchOnCountInst);
4011         continue;
4012       }
4013 
4014       VPValue *VectorStep;
4015       VPValue *ScalarStep;
4016       if (!match(&R, m_VPInstruction<VPInstruction::WideIVStep>(
4017                          m_VPValue(VectorStep), m_VPValue(ScalarStep))))
4018         continue;
4019 
4020       // Expand WideIVStep.
4021       auto *VPI = cast<VPInstruction>(&R);
4022       Type *IVTy = TypeInfo.inferScalarType(VPI);
4023       if (TypeInfo.inferScalarType(VectorStep) != IVTy) {
4024         Instruction::CastOps CastOp = IVTy->isFloatingPointTy()
4025                                           ? Instruction::UIToFP
4026                                           : Instruction::Trunc;
4027         VectorStep = Builder.createWidenCast(CastOp, VectorStep, IVTy);
4028       }
4029 
4030       assert(!match(ScalarStep, m_One()) && "Expected non-unit scalar-step");
4031       if (TypeInfo.inferScalarType(ScalarStep) != IVTy) {
4032         ScalarStep =
4033             Builder.createWidenCast(Instruction::Trunc, ScalarStep, IVTy);
4034       }
4035 
4036       VPIRFlags Flags;
4037       unsigned MulOpc;
4038       if (IVTy->isFloatingPointTy()) {
4039         MulOpc = Instruction::FMul;
4040         Flags = VPI->getFastMathFlags();
4041       } else {
4042         MulOpc = Instruction::Mul;
4043         Flags = VPIRFlags::getDefaultFlags(MulOpc);
4044       }
4045 
4046       VPInstruction *Mul = Builder.createNaryOp(
4047           MulOpc, {VectorStep, ScalarStep}, Flags, R.getDebugLoc());
4048       VectorStep = Mul;
4049       VPI->replaceAllUsesWith(VectorStep);
4050       ToRemove.push_back(VPI);
4051     }
4052   }
4053 
4054   for (VPRecipeBase *R : ToRemove)
4055     R->eraseFromParent();
4056 }
