4559     Builder.SetInsertPoint(VectorPH->getTerminator());
4560     auto *RuntimeVF = getRuntimeVF(Builder, IdxTy, State.VF);
4561     auto *LastIdx = Builder.CreateSub(RuntimeVF, One);
