4592 void VPReductionPHIRecipe::execute(VPTransformState &State) {
4593   // Reductions do not have to start at zero. They can start with
4594   // any loop invariant values.
4595   VPValue *StartVPV = getStartValue();
4596 
4597   // In order to support recurrences we need to be able to vectorize Phi nodes.
4598   // Phi nodes have cycles, so we need to vectorize them in two stages. This is
4599   // stage #1: We create a new vector PHI node with no incoming edges. We'll use
4600   // this value when we vectorize all of the instructions that use the PHI.
4601   BasicBlock *VectorPH =
4602       State.CFG.VPBB2IRBB.at(getParent()->getCFGPredecessor(0));
4603   bool ScalarPHI = State.VF.isScalar() || isInLoop();
4604   Value *StartV = State.get(StartVPV, ScalarPHI);
4605   Type *VecTy = StartV->getType();
4606 
4607   BasicBlock *HeaderBB = State.CFG.PrevBB;
4608   assert(State.CurrentParentLoop->getHeader() == HeaderBB &&
4609          "recipe must be in the vector loop header");
4610   auto *Phi = PHINode::Create(VecTy, 2, "vec.phi");
4611   Phi->insertBefore(HeaderBB->getFirstInsertionPt());
4612   State.set(this, Phi, isInLoop());
4613 
4614   Phi->addIncoming(StartV, VectorPH);
4615 }
