 940 /// early exit block.
 941 static VPValue *optimizeEarlyExitInductionUser(VPlan &Plan,
 942                                                VPTypeAnalysis &TypeInfo,
 943                                                VPBlockBase *PredVPBB,
 944                                                VPValue *Op,
 945                                                PredicatedScalarEvolution &PSE) {
 946   VPValue *Incoming, *Mask;
 947   if (!match(Op, m_ExtractLane(m_FirstActiveLane(m_VPValue(Mask)),
 948                                m_VPValue(Incoming))))
 949     return nullptr;
 950 
 951   auto *WideIV = getOptimizableIVOf(Incoming, PSE);
 952   if (!WideIV)
 953     return nullptr;
 954 
 955   auto *WideIntOrFp = dyn_cast<VPWidenIntOrFpInductionRecipe>(WideIV);
 956   if (WideIntOrFp && WideIntOrFp->getTruncInst())
 957     return nullptr;
 958 
 959   // Calculate the final index.
 960   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
 961   auto *CanonicalIV = LoopRegion->getCanonicalIV();
 962   Type *CanonicalIVType = LoopRegion->getCanonicalIVType();
 963   VPBuilder B(cast<VPBasicBlock>(PredVPBB));
 964 
 965   DebugLoc DL = cast<VPInstruction>(Op)->getDebugLoc();
 966   VPValue *FirstActiveLane =
 967       B.createNaryOp(VPInstruction::FirstActiveLane, Mask, DL);
 968   Type *FirstActiveLaneType = TypeInfo.inferScalarType(FirstActiveLane);
 969   FirstActiveLane = B.createScalarZExtOrTrunc(FirstActiveLane, CanonicalIVType,
 970                                               FirstActiveLaneType, DL);
 971   VPValue *EndValue = B.createAdd(CanonicalIV, FirstActiveLane, DL);
 972 
 973   // `getOptimizableIVOf()` always returns the pre-incremented IV, so if it
 974   // changed it means the exit is using the incremented value, so we need to
 975   // add the step.
 976   if (Incoming != WideIV) {
 977     VPValue *One = Plan.getConstantInt(CanonicalIVType, 1);
 978     EndValue = B.createAdd(EndValue, One, DL);
 979   }
 980 
 981   if (!WideIntOrFp || !WideIntOrFp->isCanonical()) {
 982     const InductionDescriptor &ID = WideIV->getInductionDescriptor();
 983     VPIRValue *Start = WideIV->getStartValue();
 984     VPValue *Step = WideIV->getStepValue();
 985     EndValue = B.createDerivedIV(
 986         ID.getKind(), dyn_cast_or_null<FPMathOperator>(ID.getInductionBinOp()),
 987         Start, EndValue, Step);
 988   }
 989 
 990   return EndValue;
