1031   if (ScalarTy->isFloatingPointTy()) {
1032     const auto &ID = WideIV->getInductionDescriptor();
1033     return B.createNaryOp(
1034         ID.getInductionBinOp()->getOpcode() == Instruction::FAdd
1035             ? Instruction::FSub
1036             : Instruction::FAdd,
1037         {EndValue, Step}, {ID.getInductionBinOp()->getFastMathFlags()});
