3216 /// Converts a tail folded vector loop region to step by
3217 /// VPInstruction::ExplicitVectorLength elements instead of VF elements each
3218 /// iteration.
3219 ///
3220 /// - Add a VPCurrentIterationPHIRecipe and related recipes to \p Plan and
3221 ///   replaces all uses except the canonical IV increment of
3222 ///   VPCanonicalIVPHIRecipe with a VPCurrentIterationPHIRecipe.
3223 ///   VPCanonicalIVPHIRecipe is used only for loop iterations counting after
3224 ///   this transformation.
3225 ///
3226 /// - The header mask is replaced with a header mask based on the EVL.
3227 ///
3228 /// - Plans with FORs have a new phi added to keep track of the EVL of the
3229 ///   previous iteration, and VPFirstOrderRecurrencePHIRecipes are replaced with
3230 ///   @llvm.vp.splice.
3231 ///
3232 /// The function uses the following definitions:
3233 ///  %StartV is the canonical induction start value.
3234 ///
3235 /// The function adds the following recipes:
3236 ///
3237 /// vector.ph:
3238 /// ...
3239 ///
3240 /// vector.body:
3241 /// ...
3242 /// %CurrentIter = CURRENT-ITERATION-PHI [ %StartV, %vector.ph ],
3243 ///                                      [ %NextIter, %vector.body ]
3244 /// %AVL = phi [ trip-count, %vector.ph ], [ %NextAVL, %vector.body ]
3245 /// %VPEVL = EXPLICIT-VECTOR-LENGTH %AVL
3246 /// ...
3247 /// %OpEVL = cast i32 %VPEVL to IVSize
3248 /// %NextIter = add IVSize %OpEVL, %CurrentIter
3249 /// %NextAVL = sub IVSize nuw %AVL, %OpEVL
3250 /// ...
3251 ///
3252 /// If MaxSafeElements is provided, the function adds the following recipes:
3253 /// vector.ph:
3254 /// ...
3255 ///
3256 /// vector.body:
3257 /// ...
3258 /// %CurrentIter = CURRENT-ITERATION-PHI [ %StartV, %vector.ph ],
3259 ///                                      [ %NextIter, %vector.body ]
3260 /// %AVL = phi [ trip-count, %vector.ph ], [ %NextAVL, %vector.body ]
3261 /// %cmp = cmp ult %AVL, MaxSafeElements
3262 /// %SAFE_AVL = select %cmp, %AVL, MaxSafeElements
3263 /// %VPEVL = EXPLICIT-VECTOR-LENGTH %SAFE_AVL
3264 /// ...
3265 /// %OpEVL = cast i32 %VPEVL to IVSize
3266 /// %NextIter = add IVSize %OpEVL, %CurrentIter
3267 /// %NextAVL = sub IVSize nuw %AVL, %OpEVL
3268 /// ...
3269 ///
3270 void VPlanTransforms::addExplicitVectorLength(
3271     VPlan &Plan, const std::optional<unsigned> &MaxSafeElements) {
3272   if (Plan.hasScalarVFOnly())
3273     return;
3274   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
3275   VPBasicBlock *Header = LoopRegion->getEntryBasicBlock();
3276 
3277   auto *CanonicalIVPHI = LoopRegion->getCanonicalIV();
3278   auto *CanIVTy = LoopRegion->getCanonicalIVType();
3279   VPValue *StartV = CanonicalIVPHI->getStartValue();
3280 
3281   // Create the CurrentIteration recipe in the vector loop.
3282   auto *CurrentIteration =
3283       new VPCurrentIterationPHIRecipe(StartV, DebugLoc::getUnknown());
3284   CurrentIteration->insertAfter(CanonicalIVPHI);
3285   VPBuilder Builder(Header, Header->getFirstNonPhi());
3286   // Create the AVL (application vector length), starting from TC -> 0 in steps
3287   // of EVL.
3288   VPPhi *AVLPhi = Builder.createScalarPhi(
3289       {Plan.getTripCount()}, DebugLoc::getCompilerGenerated(), "avl");
3290   VPValue *AVL = AVLPhi;
3291 
3292   if (MaxSafeElements) {
3293     // Support for MaxSafeDist for correct loop emission.
3294     VPValue *AVLSafe = Plan.getConstantInt(CanIVTy, *MaxSafeElements);
3295     VPValue *Cmp = Builder.createICmp(ICmpInst::ICMP_ULT, AVL, AVLSafe);
3296     AVL = Builder.createSelect(Cmp, AVL, AVLSafe, DebugLoc::getUnknown(),
3297                                "safe_avl");
3298   }
3299   auto *VPEVL = Builder.createNaryOp(VPInstruction::ExplicitVectorLength, AVL,
3300                                      DebugLoc::getUnknown(), "evl");
3301 
3302   auto *CanonicalIVIncrement =
3303       cast<VPInstruction>(CanonicalIVPHI->getBackedgeValue());
3304   Builder.setInsertPoint(CanonicalIVIncrement);
3305   VPValue *OpVPEVL = VPEVL;
3306 
3307   auto *I32Ty = Type::getInt32Ty(Plan.getContext());
3308   OpVPEVL = Builder.createScalarZExtOrTrunc(
3309       OpVPEVL, CanIVTy, I32Ty, CanonicalIVIncrement->getDebugLoc());
3310 
3311   auto *NextIter = Builder.createAdd(OpVPEVL, CurrentIteration,
3312                                      CanonicalIVIncrement->getDebugLoc(),
3313                                      "current.iteration.next",
3314                                      {CanonicalIVIncrement->hasNoUnsignedWrap(),
3315                                       CanonicalIVIncrement->hasNoSignedWrap()});
3316   CurrentIteration->addOperand(NextIter);
3317 
3318   VPValue *NextAVL =
3319       Builder.createSub(AVLPhi, OpVPEVL, DebugLoc::getCompilerGenerated(),
3320                         "avl.next", {/*NUW=*/true, /*NSW=*/false});
3321   AVLPhi->addOperand(NextAVL);
3322 
3323   fixupVFUsersForEVL(Plan, *VPEVL);
3324   removeDeadRecipes(Plan);
3325 
3326   // Replace all uses of VPCanonicalIVPHIRecipe by
3327   // VPCurrentIterationPHIRecipe except for the canonical IV increment.
3328   CanonicalIVPHI->replaceAllUsesWith(CurrentIteration);
3329   CanonicalIVIncrement->setOperand(0, CanonicalIVPHI);
3330   // TODO: support unroll factor > 1.
3331   Plan.setUF(1);
3332 }
