3334 void VPlanTransforms::convertToVariableLengthStep(VPlan &Plan) {
3335   // Find the vector loop entry by locating VPCurrentIterationPHIRecipe.
3336   // There should be only one VPCurrentIteration in the entire plan.
3337   VPCurrentIterationPHIRecipe *CurrentIteration = nullptr;
3338 
3339   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
3340            vp_depth_first_shallow(Plan.getEntry())))
3341     for (VPRecipeBase &R : VPBB->phis())
3342       if (auto *PhiR = dyn_cast<VPCurrentIterationPHIRecipe>(&R)) {
3343         assert(!CurrentIteration &&
3344                "Found multiple CurrentIteration. Only one expected");
3345         CurrentIteration = PhiR;
3346       }
3347 
3348   // Early return if it is not variable-length stepping.
3349   if (!CurrentIteration)
3350     return;
3351 
3352   VPBasicBlock *HeaderVPBB = CurrentIteration->getParent();
3353   VPValue *CurrentIterationIncr = CurrentIteration->getBackedgeValue();
3354 
3355   // Convert CurrentIteration to concrete recipe.
3356   auto *ScalarR =
3357       VPBuilder(CurrentIteration)
3358           .createScalarPhi(
3359               {CurrentIteration->getStartValue(), CurrentIterationIncr},
3360               CurrentIteration->getDebugLoc(), "current.iteration.iv");
3361   CurrentIteration->replaceAllUsesWith(ScalarR);
3362   CurrentIteration->eraseFromParent();
3363 
3364   // Replace CanonicalIVInc with CurrentIteration increment.
3365   auto *CanonicalIV = cast<VPPhi>(&*HeaderVPBB->begin());
3366   VPValue *Backedge = CanonicalIV->getIncomingValue(1);
3367   assert(match(Backedge, m_c_Add(m_Specific(CanonicalIV),
3368                                  m_Specific(&Plan.getVFxUF()))) &&
3369          "Unexpected canonical iv");
3370   Backedge->replaceAllUsesWith(CurrentIterationIncr);
3371 
3372   // Remove unused phi and increment.
3373   VPRecipeBase *CanonicalIVIncrement = Backedge->getDefiningRecipe();
3374   CanonicalIVIncrement->eraseFromParent();
3375   CanonicalIV->eraseFromParent();
3376 }
