2174 /// From the definition of llvm.experimental.get.vector.length,
2175 /// VPInstruction::ExplicitVectorLength(%AVL) = %AVL when %AVL <= VF.
2176 static bool simplifyKnownEVL(VPlan &Plan, ElementCount VF,
2177                              PredicatedScalarEvolution &PSE) {
2178   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2179            vp_depth_first_deep(Plan.getEntry()))) {
2180     for (VPRecipeBase &R : *VPBB) {
2181       VPValue *AVL;
2182       if (!match(&R, m_EVL(m_VPValue(AVL))))
2183         continue;
2184 
2185       const SCEV *AVLSCEV = vputils::getSCEVExprForVPValue(AVL, PSE);
2186       if (isa<SCEVCouldNotCompute>(AVLSCEV))
2187         continue;
2188       ScalarEvolution &SE = *PSE.getSE();
2189       const SCEV *VFSCEV = SE.getElementCount(AVLSCEV->getType(), VF);
2190       if (!SE.isKnownPredicate(CmpInst::ICMP_ULE, AVLSCEV, VFSCEV))
2191         continue;
2192 
2193       VPValue *Trunc = VPBuilder(&R).createScalarZExtOrTrunc(
2194           AVL, Type::getInt32Ty(Plan.getContext()), AVLSCEV->getType(),
2195           R.getDebugLoc());
2196       R.getVPSingleValue()->replaceAllUsesWith(Trunc);
2197       return true;
2198     }
2199   }
2200   return false;
2201 }
