2220 /// Sink users of \p FOR after the recipe defining the previous value \p
2221 /// Previous of the recurrence. \returns true if all users of \p FOR could be
2222 /// re-arranged as needed or false if it is not possible.
2223 static bool
2224 sinkRecurrenceUsersAfterPrevious(VPFirstOrderRecurrencePHIRecipe *FOR,
2225                                  VPRecipeBase *Previous,
2226                                  VPDominatorTree &VPDT) {
2227   // If Previous is a live-in (no defining recipe), it naturally dominates all
2228   // recipes in the loop, so no sinking is needed.
2229   if (!Previous)
2230     return true;
2231 
2232   // Collect recipes that need sinking.
2233   SmallVector<VPRecipeBase *> WorkList;
2234   SmallPtrSet<VPRecipeBase *, 8> Seen;
2235   Seen.insert(Previous);
2236   auto TryToPushSinkCandidate = [&](VPRecipeBase *SinkCandidate) {
2237     // The previous value must not depend on the users of the recurrence phi. In
2238     // that case, FOR is not a fixed order recurrence.
2239     if (SinkCandidate == Previous)
2240       return false;
2241 
2242     if (isa<VPHeaderPHIRecipe>(SinkCandidate) ||
2243         !Seen.insert(SinkCandidate).second ||
2244         VPDT.properlyDominates(Previous, SinkCandidate))
2245       return true;
2246 
2247     if (cannotHoistOrSinkRecipe(*SinkCandidate))
2248       return false;
2249 
2250     WorkList.push_back(SinkCandidate);
2251     return true;
2252   };
2253 
2254   // Recursively sink users of FOR after Previous.
2255   WorkList.push_back(FOR);
2256   for (unsigned I = 0; I != WorkList.size(); ++I) {
2257     VPRecipeBase *Current = WorkList[I];
2258     assert(Current->getNumDefinedValues() == 1 &&
2259            "only recipes with a single defined value expected");
2260 
2261     for (VPUser *User : Current->getVPSingleValue()->users()) {
2262       if (!TryToPushSinkCandidate(cast<VPRecipeBase>(User)))
2263         return false;
2264     }
2265   }
2266 
2267   // Keep recipes to sink ordered by dominance so earlier instructions are
2268   // processed first.
2269   sort(WorkList, [&VPDT](const VPRecipeBase *A, const VPRecipeBase *B) {
2270     return VPDT.properlyDominates(A, B);
2271   });
2272 
2273   for (VPRecipeBase *SinkCandidate : WorkList) {
2274     if (SinkCandidate == FOR)
2275       continue;
2276 
2277     SinkCandidate->moveAfter(Previous);
2278     Previous = SinkCandidate;
2279   }
2280   return true;
2281 }
