2283 /// Try to hoist \p Previous and its operands before all users of \p FOR.
2284 static bool hoistPreviousBeforeFORUsers(VPFirstOrderRecurrencePHIRecipe *FOR,
2285                                         VPRecipeBase *Previous,
2286                                         VPDominatorTree &VPDT) {
2287   if (cannotHoistOrSinkRecipe(*Previous))
2288     return false;
