2290   // Collect recipes that need hoisting.
2291   SmallVector<VPRecipeBase *> HoistCandidates;
2292   SmallPtrSet<VPRecipeBase *, 8> Visited;
2293   VPRecipeBase *HoistPoint = nullptr;
2294   // Find the closest hoist point by looking at all users of FOR and selecting
2295   // the recipe dominating all other users.
2296   for (VPUser *U : FOR->users()) {
2297     auto *R = cast<VPRecipeBase>(U);
2298     if (!HoistPoint || VPDT.properlyDominates(R, HoistPoint))
2299       HoistPoint = R;
2300   }
2301   assert(all_of(FOR->users(),
2302                 [&VPDT, HoistPoint](VPUser *U) {
2303                   auto *R = cast<VPRecipeBase>(U);
2304                   return HoistPoint == R ||
2305                          VPDT.properlyDominates(HoistPoint, R);
2306                 }) &&
2307          "HoistPoint must dominate all users of FOR");
2308 
2309   auto NeedsHoisting = [HoistPoint, &VPDT,
2310                         &Visited](VPValue *HoistCandidateV) -> VPRecipeBase * {
2311     VPRecipeBase *HoistCandidate = HoistCandidateV->getDefiningRecipe();
2312     if (!HoistCandidate)
2313       return nullptr;
2314     VPRegionBlock *EnclosingLoopRegion =
2315         HoistCandidate->getParent()->getEnclosingLoopRegion();
2316     assert((!HoistCandidate->getRegion() ||
2317             HoistCandidate->getRegion() == EnclosingLoopRegion) &&
2318            "CFG in VPlan should still be flat, without replicate regions");
