2320     if (!Visited.insert(HoistCandidate).second)
2321       return nullptr;
2322 
2323     // Candidate is outside loop region or a header phi, dominates FOR users w/o
2324     // hoisting.
2325     if (!EnclosingLoopRegion || isa<VPHeaderPHIRecipe>(HoistCandidate))
2326       return nullptr;
2327 
2328     // If we reached a recipe that dominates HoistPoint, we don't need to
2329     // hoist the recipe.
2330     if (VPDT.properlyDominates(HoistCandidate, HoistPoint))
2331       return nullptr;
2332     return HoistCandidate;
2333   };
2334 
2335   if (!NeedsHoisting(Previous->getVPSingleValue()))
2336     return true;
2337 
2338   // Recursively try to hoist Previous and its operands before all users of FOR.
2339   HoistCandidates.push_back(Previous);
2340 
