3243 ///                                      [ %NextIter, %vector.body ]
3244 /// %AVL = phi [ trip-count, %vector.ph ], [ %NextAVL, %vector.body ]
3245 /// %VPEVL = EXPLICIT-VECTOR-LENGTH %AVL
3246 /// ...
3247 /// %OpEVL = cast i32 %VPEVL to IVSize
3248 /// %NextIter = add IVSize %OpEVL, %CurrentIter
3249 /// %NextAVL = sub IVSize nuw %AVL, %OpEVL
3250 /// ...
3251 ///
3252 /// If MaxSafeElements is provided, the function adds the following recipes:
3253 /// vector.ph:
3254 /// ...
3255 ///
3256 /// vector.body:
3257 /// ...
3258 /// %CurrentIter = CURRENT-ITERATION-PHI [ %StartV, %vector.ph ],
3259 ///                                      [ %NextIter, %vector.body ]
3260 /// %AVL = phi [ trip-count, %vector.ph ], [ %NextAVL, %vector.body ]
3261 /// %cmp = cmp ult %AVL, MaxSafeElements
3262 /// %SAFE_AVL = select %cmp, %AVL, MaxSafeElements
3263 /// %VPEVL = EXPLICIT-VECTOR-LENGTH %SAFE_AVL
3264 /// ...
3265 /// %OpEVL = cast i32 %VPEVL to IVSize
3266 /// %NextIter = add IVSize %OpEVL, %CurrentIter
3267 /// %NextAVL = sub IVSize nuw %AVL, %OpEVL
3268 /// ...
3269 ///
3270 void VPlanTransforms::addExplicitVectorLength(
3271     VPlan &Plan, const std::optional<unsigned> &MaxSafeElements) {
3272   if (Plan.hasScalarVFOnly())
3273     return;
