3796 /// Expand a VPWidenPointerInductionRecipe into executable recipes, for the
3797 /// initial value, phi and backedge value. In the following example:
3798 ///
3799 ///  <x1> vector loop: {
3800 ///    vector.body:
3801 ///      EMIT ir<%ptr.iv> = WIDEN-POINTER-INDUCTION %start, %step, %vf
3802 ///      ...
3803 ///      EMIT branch-on-count ...
3804 ///  }
3805 ///
3806 /// WIDEN-POINTER-INDUCTION will get expanded to:
3807 ///
3808 ///  <x1> vector loop: {
3809 ///    vector.body:
3810 ///      EMIT-SCALAR %pointer.phi = phi %start, %ptr.ind
3811 ///      EMIT %mul = mul %stepvector, %step
3812 ///      EMIT %vector.gep = wide-ptradd %pointer.phi, %mul
3813 ///      ...
3814 ///      EMIT %ptr.ind = ptradd %pointer.phi, %vf
3815 ///      EMIT branch-on-count ...
3816 ///  }
3817 static void expandVPWidenPointerInduction(VPWidenPointerInductionRecipe *R,
3818                                           VPTypeAnalysis &TypeInfo) {
3819   VPlan *Plan = R->getParent()->getPlan();
3820   VPValue *Start = R->getStartValue();
3821   VPValue *Step = R->getStepValue();
3822   VPValue *VF = R->getVFValue();
3823 
3824   assert(R->getInductionDescriptor().getKind() ==
3825              InductionDescriptor::IK_PtrInduction &&
3826          "Not a pointer induction according to InductionDescriptor!");
3827   assert(TypeInfo.inferScalarType(R)->isPointerTy() && "Unexpected type.");
3828   assert(!R->onlyScalarsGenerated(Plan->hasScalableVF()) &&
3829          "Recipe should have been replaced");
3830 
3831   VPBuilder Builder(R);
3832   DebugLoc DL = R->getDebugLoc();
3833 
3834   // Build a scalar pointer phi.
3835   VPPhi *ScalarPtrPhi = Builder.createScalarPhi(Start, DL, "pointer.phi");
3836 
3837   // Create actual address geps that use the pointer phi as base and a
3838   // vectorized version of the step value (<step*0, ..., step*N>) as offset.
3839   Builder.setInsertPoint(R->getParent(), R->getParent()->getFirstNonPhi());
3840   Type *StepTy = TypeInfo.inferScalarType(Step);
3841   VPValue *Offset = Builder.createNaryOp(VPInstruction::StepVector, {}, StepTy);
3842   Offset = Builder.createOverflowingOp(Instruction::Mul, {Offset, Step});
3843   VPValue *PtrAdd =
3844       Builder.createWidePtrAdd(ScalarPtrPhi, Offset, DL, "vector.gep");
3845   R->replaceAllUsesWith(PtrAdd);
3846 
3847   // Create the backedge value for the scalar pointer phi.
3848   VPBasicBlock *ExitingBB = Plan->getVectorLoopRegion()->getExitingBasicBlock();
3849   Builder.setInsertPoint(ExitingBB, ExitingBB->getTerminator()->getIterator());
3850   VF = Builder.createScalarZExtOrTrunc(VF, StepTy, TypeInfo.inferScalarType(VF),
3851                                        DL);
3852   VPValue *Inc = Builder.createOverflowingOp(Instruction::Mul, {Step, VF});
3853 
3854   VPValue *InductionGEP =
3855       Builder.createPtrAdd(ScalarPtrPhi, Inc, DL, "ptr.ind");
3856   ScalarPtrPhi->addOperand(InductionGEP);
3857 }
