3871 void VPlanTransforms::expandBranchOnTwoConds(VPlan &Plan) {
3872   SmallVector<VPInstruction *> WorkList;
3873   // The transform runs after dissolving loop regions, so all VPBasicBlocks
3874   // terminated with BranchOnTwoConds are reached via a shallow traversal.
3875   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
3876            vp_depth_first_shallow(Plan.getEntry()))) {
3877     if (!VPBB->empty() && match(&VPBB->back(), m_BranchOnTwoConds()))
3878       WorkList.push_back(cast<VPInstruction>(&VPBB->back()));
3879   }
3880 
3881   // Expand BranchOnTwoConds instructions into explicit CFG with two new
3882   // single-condition branches:
3883   // 1. A branch that replaces BranchOnTwoConds, jumps to the first successor if
3884   //    the first condition is true, and otherwise jumps to a new interim block.
3885   // 2. A branch that ends the interim block, jumps to the second successor if
3886   //    the second condition is true, and otherwise jumps to the third
3887   //    successor.
3888   for (VPInstruction *Br : WorkList) {
3889     assert(Br->getNumOperands() == 2 &&
3890            "BranchOnTwoConds must have exactly 2 conditions");
3891     DebugLoc DL = Br->getDebugLoc();
3892     VPBasicBlock *BrOnTwoCondsBB = Br->getParent();
3893     const auto Successors = to_vector(BrOnTwoCondsBB->getSuccessors());
3894     assert(Successors.size() == 3 &&
3895            "BranchOnTwoConds must have exactly 3 successors");
3896 
3897     for (VPBlockBase *Succ : Successors)
3898       VPBlockUtils::disconnectBlocks(BrOnTwoCondsBB, Succ);
3899 
3900     VPValue *Cond0 = Br->getOperand(0);
3901     VPValue *Cond1 = Br->getOperand(1);
3902     VPBlockBase *Succ0 = Successors[0];
3903     VPBlockBase *Succ1 = Successors[1];
3904     VPBlockBase *Succ2 = Successors[2];
3905     assert(!Succ0->getParent() && !Succ1->getParent() && !Succ2->getParent() &&
3906            !BrOnTwoCondsBB->getParent() && "regions must already be dissolved");
3907 
3908     VPBasicBlock *InterimBB =
3909         Plan.createVPBasicBlock(BrOnTwoCondsBB->getName() + ".interim");
3910 
3911     VPBuilder(BrOnTwoCondsBB)
3912         .createNaryOp(VPInstruction::BranchOnCond, {Cond0}, DL);
3913     VPBlockUtils::connectBlocks(BrOnTwoCondsBB, Succ0);
3914     VPBlockUtils::connectBlocks(BrOnTwoCondsBB, InterimBB);
3915 
3916     VPBuilder(InterimBB).createNaryOp(VPInstruction::BranchOnCond, {Cond1}, DL);
3917     VPBlockUtils::connectBlocks(InterimBB, Succ1);
3918     VPBlockUtils::connectBlocks(InterimBB, Succ2);
3919     Br->eraseFromParent();
3920   }
