 880 /// Check if \p VPV is an untruncated wide induction, either before or after the
 881 /// increment. If so return the header IV (before the increment), otherwise
 882 /// return null.
 883 static VPWidenInductionRecipe *
 884 getOptimizableIVOf(VPValue *VPV, PredicatedScalarEvolution &PSE) {
 885   auto *WideIV = dyn_cast<VPWidenInductionRecipe>(VPV);
 886   if (WideIV) {
 887     // VPV itself is a wide induction, separately compute the end value for exit
 888     // users if it is not a truncated IV.
 889     auto *IntOrFpIV = dyn_cast<VPWidenIntOrFpInductionRecipe>(WideIV);
 890     return (IntOrFpIV && IntOrFpIV->getTruncInst()) ? nullptr : WideIV;
 891   }
 892 
 893   // Check if VPV is an optimizable induction increment.
 894   VPRecipeBase *Def = VPV->getDefiningRecipe();
 895   if (!Def || Def->getNumOperands() != 2)
 896     return nullptr;
 897   WideIV = dyn_cast<VPWidenInductionRecipe>(Def->getOperand(0));
 898   if (!WideIV)
 899     WideIV = dyn_cast<VPWidenInductionRecipe>(Def->getOperand(1));
 900   if (!WideIV)
 901     return nullptr;
 902 
 903   auto IsWideIVInc = [&]() {
 904     auto &ID = WideIV->getInductionDescriptor();
 905 
 906     // Check if VPV increments the induction by the induction step.
 907     VPValue *IVStep = WideIV->getStepValue();
 908     switch (ID.getInductionOpcode()) {
 909     case Instruction::Add:
 910       return match(VPV, m_c_Add(m_Specific(WideIV), m_Specific(IVStep)));
 911     case Instruction::FAdd:
 912       return match(VPV, m_c_FAdd(m_Specific(WideIV), m_Specific(IVStep)));
 913     case Instruction::FSub:
 914       return match(VPV, m_Binary<Instruction::FSub>(m_Specific(WideIV),
 915                                                     m_Specific(IVStep)));
 916     case Instruction::Sub: {
 917       // IVStep will be the negated step of the subtraction. Check if Step == -1
 918       // * IVStep.
 919       VPValue *Step;
 920       if (!match(VPV, m_Sub(m_VPValue(), m_VPValue(Step))))
 921         return false;
 922       const SCEV *IVStepSCEV = vputils::getSCEVExprForVPValue(IVStep, PSE);
 923       const SCEV *StepSCEV = vputils::getSCEVExprForVPValue(Step, PSE);
 924       ScalarEvolution &SE = *PSE.getSE();
 925       return !isa<SCEVCouldNotCompute>(IVStepSCEV) &&
 926              !isa<SCEVCouldNotCompute>(StepSCEV) &&
 927              IVStepSCEV == SE.getNegativeSCEV(StepSCEV);
 928     }
 929     default:
 930       return ID.getKind() == InductionDescriptor::IK_PtrInduction &&
 931              match(VPV, m_GetElementPtr(m_Specific(WideIV),
 932                                         m_Specific(WideIV->getStepValue())));
 933     }
 934     llvm_unreachable("should have been covered by switch above");
 935   };
 936   return IsWideIVInc() ? WideIV : nullptr;
 937 }
