1116       .Case([](const VPWidenIntrinsicRecipe *I) {
1117         return std::make_pair(true, I->getVectorIntrinsicID());
1118       })
1119       .Case<VPVectorPointerRecipe, VPPredInstPHIRecipe>([](auto *I) {
1120         // For recipes that do not directly map to LLVM IR instructions,
1121         // assign opcodes after the last VPInstruction opcode (which is also
1122         // after the last IR Instruction opcode), based on the VPRecipeID.
1123         return std::make_pair(false,
1124                               VPInstruction::OpsEnd + 1 + I->getVPRecipeID());
