1129 /// Try to fold \p R using InstSimplifyFolder. Will succeed and return a
1130 /// non-nullptr VPValue for a handled opcode or intrinsic ID if corresponding \p
1131 /// Operands are foldable live-ins.
1132 static VPIRValue *tryToFoldLiveIns(VPSingleDefRecipe &R,
1133                                    ArrayRef<VPValue *> Operands,
1134                                    const DataLayout &DL,
1135                                    VPTypeAnalysis &TypeInfo) {
1136   auto OpcodeOrIID = getOpcodeOrIntrinsicID(&R);
1137   if (!OpcodeOrIID)
1138     return nullptr;
1139 
1140   SmallVector<Value *, 4> Ops;
1141   for (VPValue *Op : Operands) {
1142     if (!match(Op, m_LiveIn()))
1143       return nullptr;
1144     Value *V = Op->getUnderlyingValue();
1145     if (!V)
1146       return nullptr;
1147     Ops.push_back(V);
1148   }
1149 
1150   auto FoldToIRValue = [&]() -> Value * {
1151     InstSimplifyFolder Folder(DL);
1152     if (OpcodeOrIID->first) {
1153       if (R.getNumOperands() != 2)
1154         return nullptr;
1155       unsigned ID = OpcodeOrIID->second;
1156       return Folder.FoldBinaryIntrinsic(ID, Ops[0], Ops[1],
1157                                         TypeInfo.inferScalarType(&R));
1158     }
1159     unsigned Opcode = OpcodeOrIID->second;
1160     if (Instruction::isBinaryOp(Opcode))
1161       return Folder.FoldBinOp(static_cast<Instruction::BinaryOps>(Opcode),
1162                               Ops[0], Ops[1]);
1163     if (Instruction::isCast(Opcode))
1164       return Folder.FoldCast(static_cast<Instruction::CastOps>(Opcode), Ops[0],
1165                              TypeInfo.inferScalarType(R.getVPSingleValue()));
1166     switch (Opcode) {
1167     case VPInstruction::LogicalAnd:
1168       return Folder.FoldSelect(Ops[0], Ops[1],
1169                                ConstantInt::getNullValue(Ops[1]->getType()));
1170     case VPInstruction::Not:
1171       return Folder.FoldBinOp(Instruction::BinaryOps::Xor, Ops[0],
1172                               Constant::getAllOnesValue(Ops[0]->getType()));
1173     case Instruction::Select:
1174       return Folder.FoldSelect(Ops[0], Ops[1], Ops[2]);
1175     case Instruction::ICmp:
1176     case Instruction::FCmp:
1177       return Folder.FoldCmp(cast<VPRecipeWithIRFlags>(R).getPredicate(), Ops[0],
1178                             Ops[1]);
1179     case Instruction::GetElementPtr: {
1180       auto &RFlags = cast<VPRecipeWithIRFlags>(R);
1181       auto *GEP = cast<GetElementPtrInst>(RFlags.getUnderlyingInstr());
1182       return Folder.FoldGEP(GEP->getSourceElementType(), Ops[0],
1183                             drop_begin(Ops), RFlags.getGEPNoWrapFlags());
1184     }
1185     case VPInstruction::PtrAdd:
1186     case VPInstruction::WidePtrAdd:
1187       return Folder.FoldGEP(IntegerType::getInt8Ty(TypeInfo.getContext()),
1188                             Ops[0], Ops[1],
1189                             cast<VPRecipeWithIRFlags>(R).getGEPNoWrapFlags());
1190     // An extract of a live-in is an extract of a broadcast, so return the
1191     // broadcasted element.
1192     case Instruction::ExtractElement:
1193       assert(!Ops[0]->getType()->isVectorTy() && "Live-ins should be scalar");
1194       return Ops[0];
1195     }
1196     return nullptr;
1197   };
1198 
1199   if (Value *V = FoldToIRValue())
1200     return R.getParent()->getPlan()->getOrAddLiveIn(V);
1201   return nullptr;
1202 }
