1204 /// Try to simplify VPSingleDefRecipe \p Def.
1205 static void simplifyRecipe(VPSingleDefRecipe *Def, VPTypeAnalysis &TypeInfo) {
1206   VPlan *Plan = Def->getParent()->getPlan();
1207 
1208   // Simplification of live-in IR values for SingleDef recipes using
1209   // InstSimplifyFolder.
1210   const DataLayout &DL =
1211       Plan->getScalarHeader()->getIRBasicBlock()->getDataLayout();
1212   if (VPValue *V = tryToFoldLiveIns(*Def, Def->operands(), DL, TypeInfo))
1213     return Def->replaceAllUsesWith(V);
1214 
1215   // Fold PredPHI LiveIn -> LiveIn.
1216   if (auto *PredPHI = dyn_cast<VPPredInstPHIRecipe>(Def)) {
1217     VPValue *Op = PredPHI->getOperand(0);
1218     if (isa<VPIRValue>(Op))
1219       PredPHI->replaceAllUsesWith(Op);
1220   }
1221 
1222   VPBuilder Builder(Def);
1223 
1224   // Avoid replacing VPInstructions with underlying values with new
1225   // VPInstructions, as we would fail to create widen/replicate recpes from the
1226   // new VPInstructions without an underlying value, and miss out on some
1227   // transformations that only apply to widened/replicated recipes later, by
1228   // doing so.
1229   // TODO: We should also not replace non-VPInstructions like VPWidenRecipe with
1230   // VPInstructions without underlying values, as those will get skipped during
1231   // cost computation.
1232   bool CanCreateNewRecipe =
1233       !isa<VPInstruction>(Def) || !Def->getUnderlyingValue();
1234 
1235   VPValue *A;
1236   if (match(Def, m_Trunc(m_ZExtOrSExt(m_VPValue(A))))) {
1237     Type *TruncTy = TypeInfo.inferScalarType(Def);
1238     Type *ATy = TypeInfo.inferScalarType(A);
1239     if (TruncTy == ATy) {
1240       Def->replaceAllUsesWith(A);
1241     } else {
1242       // Don't replace a non-widened cast recipe with a widened cast.
1243       if (!isa<VPWidenCastRecipe>(Def))
1244         return;
1245       if (ATy->getScalarSizeInBits() < TruncTy->getScalarSizeInBits()) {
1246 
1247         unsigned ExtOpcode = match(Def->getOperand(0), m_SExt(m_VPValue()))
1248                                  ? Instruction::SExt
1249                                  : Instruction::ZExt;
1250         auto *Ext = Builder.createWidenCast(Instruction::CastOps(ExtOpcode), A,
1251                                             TruncTy);
1252         if (auto *UnderlyingExt = Def->getOperand(0)->getUnderlyingValue()) {
1253           // UnderlyingExt has distinct return type, used to retain legacy cost.
1254           Ext->setUnderlyingValue(UnderlyingExt);
1255         }
1256         Def->replaceAllUsesWith(Ext);
1257       } else if (ATy->getScalarSizeInBits() > TruncTy->getScalarSizeInBits()) {
1258         auto *Trunc = Builder.createWidenCast(Instruction::Trunc, A, TruncTy);
1259         Def->replaceAllUsesWith(Trunc);
1260       }
1261     }
1262 #ifndef NDEBUG
1263     // Verify that the cached type info is for both A and its users is still
1264     // accurate by comparing it to freshly computed types.
1265     VPTypeAnalysis TypeInfo2(*Plan);
1266     assert(TypeInfo.inferScalarType(A) == TypeInfo2.inferScalarType(A));
1267     for (VPUser *U : A->users()) {
1268       auto *R = cast<VPRecipeBase>(U);
1269       for (VPValue *VPV : R->definedValues())
1270         assert(TypeInfo.inferScalarType(VPV) == TypeInfo2.inferScalarType(VPV));
1271     }
1272 #endif
1273   }
1274 
1275   // Simplify (X && Y) | (X && !Y) -> X.
1276   // TODO: Split up into simpler, modular combines: (X && Y) | (X && Z) into X
1277   // && (Y | Z) and (X | !X) into true. This requires queuing newly created
1278   // recipes to be visited during simplification.
1279   VPValue *X, *Y, *Z;
1280   if (match(Def,
1281             m_c_BinaryOr(m_LogicalAnd(m_VPValue(X), m_VPValue(Y)),
1282                          m_LogicalAnd(m_Deferred(X), m_Not(m_Deferred(Y)))))) {
1283     Def->replaceAllUsesWith(X);
1284     Def->eraseFromParent();
1285     return;
1286   }
1287 
1288   // x | 1 -> 1
1289   if (match(Def, m_c_BinaryOr(m_VPValue(X), m_AllOnes())))
1290     return Def->replaceAllUsesWith(Def->getOperand(Def->getOperand(0) == X));
1291 
1292   // x | 0 -> x
1293   if (match(Def, m_c_BinaryOr(m_VPValue(X), m_ZeroInt())))
1294     return Def->replaceAllUsesWith(X);
1295 
1296   // x | !x -> AllOnes
1297   if (match(Def, m_c_BinaryOr(m_VPValue(X), m_Not(m_Deferred(X))))) {
1298     return Def->replaceAllUsesWith(Plan->getOrAddLiveIn(
1299         ConstantInt::getAllOnesValue(TypeInfo.inferScalarType(Def))));
