4058 void VPlanTransforms::handleUncountableEarlyExits(VPlan &Plan,
4059                                                   VPBasicBlock *HeaderVPBB,
4060                                                   VPBasicBlock *LatchVPBB,
4061                                                   VPBasicBlock *MiddleVPBB) {
4062   struct EarlyExitInfo {
4063     VPBasicBlock *EarlyExitingVPBB;
4064     VPIRBasicBlock *EarlyExitVPBB;
4065     VPValue *CondToExit;
4066   };
4067 
4068   VPDominatorTree VPDT(Plan);
4069   VPBuilder Builder(LatchVPBB->getTerminator());
4070   SmallVector<EarlyExitInfo> Exits;
4071   for (VPIRBasicBlock *ExitBlock : Plan.getExitBlocks()) {
4072     for (VPBlockBase *Pred : to_vector(ExitBlock->getPredecessors())) {
4073       if (Pred == MiddleVPBB)
4074         continue;
4075       // Collect condition for this early exit.
4076       auto *EarlyExitingVPBB = cast<VPBasicBlock>(Pred);
4077       VPBlockBase *TrueSucc = EarlyExitingVPBB->getSuccessors()[0];
4078       VPValue *CondOfEarlyExitingVPBB;
4079       [[maybe_unused]] bool Matched =
4080           match(EarlyExitingVPBB->getTerminator(),
4081                 m_BranchOnCond(m_VPValue(CondOfEarlyExitingVPBB)));
4082       assert(Matched && "Terminator must be BranchOnCond");
4083       auto *CondToEarlyExit = TrueSucc == ExitBlock
4084                                   ? CondOfEarlyExitingVPBB
4085                                   : Builder.createNot(CondOfEarlyExitingVPBB);
4086       assert((isa<VPIRValue>(CondOfEarlyExitingVPBB) ||
4087               VPDT.properlyDominates(
4088                   CondOfEarlyExitingVPBB->getDefiningRecipe()->getParent(),
4089                   LatchVPBB)) &&
4090              "exit condition must dominate the latch");
4091       Exits.push_back({
4092           EarlyExitingVPBB,
4093           ExitBlock,
4094           CondToEarlyExit,
4095       });
4096     }
4097   }
4098 
4099   assert(!Exits.empty() && "must have at least one early exit");
4100   // Sort exits by dominance to get the correct program order.
4101   llvm::sort(Exits, [&VPDT](const EarlyExitInfo &A, const EarlyExitInfo &B) {
4102     return VPDT.properlyDominates(A.EarlyExitingVPBB, B.EarlyExitingVPBB);
4103   });
4104 
4105   // Build the AnyOf condition for the latch terminator using logical OR
4106   // to avoid poison propagation from later exit conditions when an earlier
4107   // exit is taken.
4108   VPValue *Combined = Exits[0].CondToExit;
4109   for (const EarlyExitInfo &Info : drop_begin(Exits))
4110     Combined = Builder.createLogicalOr(Combined, Info.CondToExit);
4111 
4112   VPValue *IsAnyExitTaken =
4113       Builder.createNaryOp(VPInstruction::AnyOf, {Combined});
4114 
4115   // Create the vector.early.exit blocks.
4116   SmallVector<VPBasicBlock *> VectorEarlyExitVPBBs(Exits.size());
4117   for (unsigned Idx = 0; Idx != Exits.size(); ++Idx) {
4118     Twine BlockSuffix = Exits.size() == 1 ? "" : Twine(".") + Twine(Idx);
4119     VPBasicBlock *VectorEarlyExitVPBB =
4120         Plan.createVPBasicBlock("vector.early.exit" + BlockSuffix);
4121     VectorEarlyExitVPBBs[Idx] = VectorEarlyExitVPBB;
4122   }
4123 
4124   // Create the dispatch block (or reuse the single exit block if only one
4125   // exit). The dispatch block computes the first active lane of the combined
4126   // condition and, for multiple exits, chains through conditions to determine
4127   // which exit to take.
4128   VPBasicBlock *DispatchVPBB =
4129       Exits.size() == 1 ? VectorEarlyExitVPBBs[0]
4130                         : Plan.createVPBasicBlock("vector.early.exit.check");
4131   VPBuilder DispatchBuilder(DispatchVPBB, DispatchVPBB->begin());
4132   VPValue *FirstActiveLane =
4133       DispatchBuilder.createNaryOp(VPInstruction::FirstActiveLane, {Combined},
4134                                    DebugLoc::getUnknown(), "first.active.lane");
4135 
4136   // For each early exit, disconnect the original exiting block
4137   // (early.exiting.I) from the exit block (ir-bb<exit.I>) and route through a
4138   // new vector.early.exit block. Update ir-bb<exit.I>'s phis to extract their
4139   // values at the first active lane:
4140   //
4141   // Input:
4142   //  early.exiting.I:
4143   //     ...
4144   //    EMIT branch-on-cond vp<%cond.I>
4145   //  Successor(s): in.loop.succ, ir-bb<exit.I>
4146   //
4147   //  ir-bb<exit.I>:
4148   //    IR %phi = phi [ vp<%incoming.I>, early.exiting.I ], ...
4149   //
4150   // Output:
4151   //  early.exiting.I:
4152   //    ...
4153   //  Successor(s): in.loop.succ
4154   //
4155   //  vector.early.exit.I:
4156   //    EMIT vp<%exit.val> = extract-lane vp<%first.lane>, vp<%incoming.I>
4157   //  Successor(s): ir-bb<exit.I>
4158   //
4159   //  ir-bb<exit.I>:
4160   //    IR %phi = phi ... (extra operand: vp<%exit.val> from
4161   //                                      vector.early.exit.I)
4162   //
4163   for (auto [Exit, VectorEarlyExitVPBB] :
4164        zip_equal(Exits, VectorEarlyExitVPBBs)) {
4165     auto &[EarlyExitingVPBB, EarlyExitVPBB, _] = Exit;
4166     // Adjust the phi nodes in EarlyExitVPBB.
4167     //   1. remove incoming values from EarlyExitingVPBB,
4168     //   2. extract the incoming value at FirstActiveLane
4169     //   3. add back the extracts as last operands for the phis
4170     // Then adjust the CFG, removing the edge between EarlyExitingVPBB and
4171     // EarlyExitVPBB and adding a new edge between VectorEarlyExitVPBB and
4172     // EarlyExitVPBB. The extracts at FirstActiveLane are now the incoming
4173     // values from VectorEarlyExitVPBB.
4174     for (VPRecipeBase &R : EarlyExitVPBB->phis()) {
4175       auto *ExitIRI = cast<VPIRPhi>(&R);
4176       VPValue *IncomingVal =
4177           ExitIRI->getIncomingValueForBlock(EarlyExitingVPBB);
4178       VPValue *NewIncoming = IncomingVal;
4179       if (!isa<VPIRValue>(IncomingVal)) {
4180         VPBuilder EarlyExitBuilder(VectorEarlyExitVPBB);
4181         NewIncoming = EarlyExitBuilder.createNaryOp(
4182             VPInstruction::ExtractLane, {FirstActiveLane, IncomingVal},
4183             DebugLoc::getUnknown(), "early.exit.value");
4184       }
